const articles=document.querySelector(".articles"),avatarDiv=document.querySelector(".avatar");function addRepo(e){const t=document.createElement("a"),a=document.createElement("article"),n=document.createElement("h3"),r=document.createElement("p");if(n.innerText=e.name,r.innerText=e.description,t.href=e.html_url,a.append(n),a.append(r),null!=e.language){const t=document.createElement("span");t.className="tag",t.innerText=e.language,a.append(t)}t.append(a),t.target="_blank",t.rel="noreferrer",articles.append(t)}fetch("https://api.github.com/users/alt-art").then((e=>e.json())).then((e=>{const t=document.createElement("img");t.src=e.avatar_url,t.alt="Github avatar",avatarDiv.appendChild(t)})).catch((e=>{})),fetch("https://api.github.com/users/alt-art/repos?type=owner&sort=updated").then((e=>e.json())).then((e=>{e.filter((e=>!e.fork)).forEach((e=>{addRepo(e)}))})).catch((e=>{}));